const now = Date.now();
const items = $input.all();

const stageLabels = {
  appointmentscheduled: 'Appointment Scheduled',
  qualifiedtobuy: 'Qualified To Buy',
  presentationscheduled: 'Presentation Scheduled',
  decisionmakerboughtin: 'Decision Maker Bought-In',
  contractsent: 'Contract Sent',
  closedwon: 'Closed Won',
  closedlost: 'Closed Lost'
};

const stuckStages = ['presentationscheduled', 'decisionmakerboughtin', 'contractsent'];

const deals = items.map(item => {
  const p = item.json.properties;
  const closedate = parseInt(p.closedate?.value || 0);
  const lastModified = parseInt(p.hs_lastmodifieddate?.value || 0);
  const daysStale = Math.floor((now - lastModified) / (1000 * 60 * 60 * 24));
  const daysOverdue = closedate ? Math.floor((now - closedate) / (1000 * 60 * 60 * 24)) : null;

  return {
    dealId: item.json.dealId,
    dealname: p.dealname?.value || 'Unknown',
    amount: parseFloat(p.amount?.value || 0),
    stage: p.dealstage?.value || 'unknown',
    stageLabel: stageLabels[p.dealstage?.value] || p.dealstage?.value,
    closedate: closedate ? new Date(closedate).toISOString().split('T')[0] : null,
    daysStale,
    daysOverdue,
    overdueTasks: parseInt(p.hs_number_of_overdue_tasks?.value || 0),
    isOverdue: daysOverdue !== null && daysOverdue > 0,
    isStuck: stuckStages.includes(p.dealstage?.value)
  };
});

// Stage breakdown
const stageCounts = {};
const stageAmounts = {};
deals.forEach(d => {
  stageCounts[d.stageLabel] = (stageCounts[d.stageLabel] || 0) + 1;
  stageAmounts[d.stageLabel] = (stageAmounts[d.stageLabel] || 0) + d.amount;
});

// At-risk deals (stuck stages only)
const atRiskDeals = deals.filter(d => d.isStuck);
const totalAtRisk = atRiskDeals.reduce((sum, d) => sum + d.amount, 0);
const atRiskDealIds = atRiskDeals.map(d => d.dealId);

return [{
  json: {
    reportDate: new Date().toISOString().split('T')[0],
    totalDeals: deals.length,
    stageCounts,
    stageAmounts,
    totalAtRisk,
    atRiskDealIds,
    atRiskDeals: atRiskDeals.map(d => ({
      dealId: d.dealId,
      dealname: d.dealname,
      amount: d.amount,
      stageLabel: d.stageLabel,
      daysStale: d.daysStale,
      daysOverdue: d.daysOverdue,
      isOverdue: d.isOverdue,
      overdueTasks: d.overdueTasks
    }))
  }
}];

