const data = $input.first().json.output;

const messages = [];

// Message 1: Header + Pipeline Summary
let msg1 = `<b>📊 Daily Sales Report — ${data.reportDate}</b>\n\n`;
msg1 += `<b>Pipeline Overview</b>\n`;
msg1 += `Total Deals: ${data.summary.totalDeals}\n`;
msg1 += `💰 Total At Risk: $${(131000).toLocaleString()}\n\n`;
msg1 += `<b>Stage Breakdown:</b>\n`;
msg1 += data.summary.stageBreakdown
  .map(s => `• ${s.stage}: ${s.count} deals / $${s.amount.toLocaleString()}`)
  .join('\n');
messages.push({ json: { text: msg1 } });

// Messages 2+: Deals (3 per message)
const deals = data.atRiskDeals;
const chunkSize = 3;
for (let i = 0; i < deals.length; i += chunkSize) {
  const chunk = deals.slice(i, i + chunkSize);
  const part = Math.floor(i / chunkSize) + 1;
  const total = Math.ceil(deals.length / chunkSize);

  let msg = `<b>🚨 At-Risk Deals (Part ${part}/${total})</b>\n\n`;
  msg += chunk.map(d =>
    `<b>${d.priority.toUpperCase()} — ${d.dealname}</b>\n` +
    `💵 $${d.amount.toLocaleString()} | ${d.stage}\n` +
    `⚠️ ${d.problem}\n` +
    `✅ ${d.recommendation}`
  ).join('\n\n');
  messages.push({ json: { text: msg } });
}

// Last message: Priority Actions
let msgLast = `<b>🎯 Top Priority Actions:</b>\n\n`;
msgLast += data.topPriorityActions
  .map((a, i) => `${i + 1}. ${a}`)
  .join('\n\n');
messages.push({ json: { text: msgLast } });

return messages;
